input.command:
python3 << 'EOF'
import json, glob, re
from collections import Counter

# Probe the issues
mismatch_examples = []
no_state_examples = []
short_conv_examples = []
bad_tool_role_examples = []

for fp in sorted(glob.glob('*.jsonl')):
    with open(fp) as f:
        for line_no, line in enumerate(f, 1):
            r = json.loads(line)
            gt_term = r['ground_truth']['terminal_state']
            graph_terms = r['workflow_graph']['terminal']
            if gt_term not in graph_terms and len(mismatch_examples) < 5:
                mismatch_examples.append((fp, r['conversation_id'], gt_term, graph_terms))

            if len(r['messages']) <= 2 and len(short_conv_examples) < 3:
                short_conv_examples.append((fp, r['conversation_id'], len(r['messages']),
                                            [m['role'] for m in r['messages']]))

            for m in r['messages']:
                if m['role'] == 'assistant':
                    c = m.get('content') or ''
                    if not re.search(r'\[STATE:', c) and len(no_state_examples) < 5:
                        no_state_examples.append((fp, r['conversation_id'], c[:200]))
                if m['role'] == 'tool':
                    try:
                        json.loads(m.get('content') or '')
                    except Exception:
                        if len(bad_tool_role_examples) < 5:
                            bad_tool_role_examples.append((fp, r['conversation_id'],
                                                           (m.get('content') or '')[:200]))

print('=== Terminal mismatch examples ===')
for e in mismatch_examples:
    print(f'  {e[1]} in {e[0][:60]}: gt={e[2]!r} not in {e[3]}')
print()
print('=== Short conversations (<=2 msgs) ===')
for e in short_conv_examples:
    print(f'  {e}')
print()
print('=== Assistant msgs missing [STATE:] ===')
for e in no_state_examples:
    print(f'  {e[1]} | {e[2]!r}')
print()
print('=== Bad tool-role JSON (sample) ===')
for e in bad_tool_role_examples:
    print(f'  {e[1]} | {e[2]!r}')
EOF
